diff --git a/cmd/entire/cli/agent/external/capabilities.go b/cmd/entire/cli/agent/external/capabilities.go
new file mode 100644
index 0000000..e0c2493
--- /dev/null
+++ b/cmd/entire/cli/agent/external/capabilities.go
@@ -0,0 +1,183 @@
+package external
+
+import (
+	"context"
+	"io"
+
+	"github.com/entireio/cli/cmd/entire/cli/agent"
+	"github.com/entireio/cli/cmd/entire/cli/agent/types"
+)
+
+// Wrap returns the Agent wrapped with the appropriate interface
+// implementations based on the capabilities declared in its info response.
+// The returned value satisfies agent.Agent and whichever optional interfaces
+// the external binary declared support for.
+//
+// We cannot use Go embedding because *Agent implements ALL optional interface
+// methods, and embedding would expose all of them regardless of capabilities.
+// Instead, each wrapper explicitly forwards only the interfaces it should expose.
+func Wrap(ea *Agent) agent.Agent {
+	caps := ea.info.Capabilities
+
+	base := baseAgent{ea: ea}
+
+	switch {
+	case caps.Hooks && caps.TranscriptAnalyzer && caps.TokenCalculator && caps.TextGenerator && caps.HookResponseWriter && caps.SubagentAwareExtractor:
+		return &fullAgent{baseAgent: base}
+	case caps.Hooks && caps.TranscriptAnalyzer:
+		return &hooksAnalyzerAgent{baseAgent: base}
+	case caps.Hooks:
+		return &hooksAgent{baseAgent: base}
+	case caps.TranscriptAnalyzer:
+		return &analyzerAgent{baseAgent: base}
+	default:
+		return &base
+	}
+}
+
+// --- baseAgent: only agent.Agent methods ---
+
+type baseAgent struct{ ea *Agent }
+
+func (b *baseAgent) Name() types.AgentName                                       { return b.ea.Name() }
+func (b *baseAgent) Type() types.AgentType                                       { return b.ea.Type() }
+func (b *baseAgent) Description() string                                         { return b.ea.Description() }
+func (b *baseAgent) IsPreview() bool                                             { return b.ea.IsPreview() }
+func (b *baseAgent) DetectPresence(ctx context.Context) (bool, error)            { return b.ea.DetectPresence(ctx) }
+func (b *baseAgent) ProtectedDirs() []string                                     { return b.ea.ProtectedDirs() }
+func (b *baseAgent) ReadTranscript(ref string) ([]byte, error)                   { return b.ea.ReadTranscript(ref) }
+func (b *baseAgent) ChunkTranscript(ctx context.Context, c []byte, m int) ([][]byte, error) { return b.ea.ChunkTranscript(ctx, c, m) }
+func (b *baseAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error)        { return b.ea.ReassembleTranscript(chunks) }
+func (b *baseAgent) GetSessionID(input *agent.HookInput) string                  { return b.ea.GetSessionID(input) }
+func (b *baseAgent) GetSessionDir(repoPath string) (string, error)               { return b.ea.GetSessionDir(repoPath) }
+func (b *baseAgent) ResolveSessionFile(dir, id string) string                    { return b.ea.ResolveSessionFile(dir, id) }
+func (b *baseAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) { return b.ea.ReadSession(input) }
+func (b *baseAgent) WriteSession(ctx context.Context, s *agent.AgentSession) error { return b.ea.WriteSession(ctx, s) }
+func (b *baseAgent) FormatResumeCommand(id string) string                        { return b.ea.FormatResumeCommand(id) }
+
+// --- hooksAgent: agent.Agent + HookSupport ---
+
+type hooksAgent struct{ baseAgent }
+
+func (h *hooksAgent) HookNames() []string { return h.ea.HookNames() }
+func (h *hooksAgent) ParseHookEvent(ctx context.Context, name string, stdin io.Reader) (*agent.Event, error) {
+	return h.ea.ParseHookEvent(ctx, name, stdin)
+}
+func (h *hooksAgent) InstallHooks(ctx context.Context, localDev bool, force bool) (int, error) {
+	return h.ea.InstallHooks(ctx, localDev, force)
+}
+func (h *hooksAgent) UninstallHooks(ctx context.Context) error { return h.ea.UninstallHooks(ctx) }
+func (h *hooksAgent) AreHooksInstalled(ctx context.Context) bool { return h.ea.AreHooksInstalled(ctx) }
+
+var _ agent.HookSupport = (*hooksAgent)(nil)
+
+// --- analyzerAgent: agent.Agent + TranscriptAnalyzer ---
+
+type analyzerAgent struct{ baseAgent }
+
+func (a *analyzerAgent) GetTranscriptPosition(path string) (int, error) {
+	return a.ea.GetTranscriptPosition(path)
+}
+func (a *analyzerAgent) ExtractModifiedFilesFromOffset(path string, offset int) ([]string, int, error) {
+	return a.ea.ExtractModifiedFilesFromOffset(path, offset)
+}
+func (a *analyzerAgent) ExtractPrompts(ref string, offset int) ([]string, error) {
+	return a.ea.ExtractPrompts(ref, offset)
+}
+func (a *analyzerAgent) ExtractSummary(ref string) (string, error) {
+	return a.ea.ExtractSummary(ref)
+}
+
+var _ agent.TranscriptAnalyzer = (*analyzerAgent)(nil)
+
+// --- hooksAnalyzerAgent: agent.Agent + HookSupport + TranscriptAnalyzer ---
+
+type hooksAnalyzerAgent struct{ baseAgent }
+
+func (ha *hooksAnalyzerAgent) HookNames() []string { return ha.ea.HookNames() }
+func (ha *hooksAnalyzerAgent) ParseHookEvent(ctx context.Context, name string, stdin io.Reader) (*agent.Event, error) {
+	return ha.ea.ParseHookEvent(ctx, name, stdin)
+}
+func (ha *hooksAnalyzerAgent) InstallHooks(ctx context.Context, localDev bool, force bool) (int, error) {
+	return ha.ea.InstallHooks(ctx, localDev, force)
+}
+func (ha *hooksAnalyzerAgent) UninstallHooks(ctx context.Context) error { return ha.ea.UninstallHooks(ctx) }
+func (ha *hooksAnalyzerAgent) AreHooksInstalled(ctx context.Context) bool { return ha.ea.AreHooksInstalled(ctx) }
+func (ha *hooksAnalyzerAgent) GetTranscriptPosition(path string) (int, error) {
+	return ha.ea.GetTranscriptPosition(path)
+}
+func (ha *hooksAnalyzerAgent) ExtractModifiedFilesFromOffset(path string, offset int) ([]string, int, error) {
+	return ha.ea.ExtractModifiedFilesFromOffset(path, offset)
+}
+func (ha *hooksAnalyzerAgent) ExtractPrompts(ref string, offset int) ([]string, error) {
+	return ha.ea.ExtractPrompts(ref, offset)
+}
+func (ha *hooksAnalyzerAgent) ExtractSummary(ref string) (string, error) {
+	return ha.ea.ExtractSummary(ref)
+}
+
+var (
+	_ agent.HookSupport        = (*hooksAnalyzerAgent)(nil)
+	_ agent.TranscriptAnalyzer = (*hooksAnalyzerAgent)(nil)
+)
+
+// --- fullAgent: all optional interfaces ---
+
+type fullAgent struct{ baseAgent }
+
+// HookSupport
+func (f *fullAgent) HookNames() []string { return f.ea.HookNames() }
+func (f *fullAgent) ParseHookEvent(ctx context.Context, name string, stdin io.Reader) (*agent.Event, error) {
+	return f.ea.ParseHookEvent(ctx, name, stdin)
+}
+func (f *fullAgent) InstallHooks(ctx context.Context, localDev bool, force bool) (int, error) {
+	return f.ea.InstallHooks(ctx, localDev, force)
+}
+func (f *fullAgent) UninstallHooks(ctx context.Context) error { return f.ea.UninstallHooks(ctx) }
+func (f *fullAgent) AreHooksInstalled(ctx context.Context) bool { return f.ea.AreHooksInstalled(ctx) }
+
+// TranscriptAnalyzer
+func (f *fullAgent) GetTranscriptPosition(path string) (int, error) {
+	return f.ea.GetTranscriptPosition(path)
+}
+func (f *fullAgent) ExtractModifiedFilesFromOffset(path string, offset int) ([]string, int, error) {
+	return f.ea.ExtractModifiedFilesFromOffset(path, offset)
+}
+func (f *fullAgent) ExtractPrompts(ref string, offset int) ([]string, error) {
+	return f.ea.ExtractPrompts(ref, offset)
+}
+func (f *fullAgent) ExtractSummary(ref string) (string, error) {
+	return f.ea.ExtractSummary(ref)
+}
+
+// TokenCalculator
+func (f *fullAgent) CalculateTokenUsage(data []byte, offset int) (*agent.TokenUsage, error) {
+	return f.ea.CalculateTokenUsage(data, offset)
+}
+
+// TextGenerator
+func (f *fullAgent) GenerateText(ctx context.Context, prompt string, model string) (string, error) {
+	return f.ea.GenerateText(ctx, prompt, model)
+}
+
+// HookResponseWriter
+func (f *fullAgent) WriteHookResponse(message string) error {
+	return f.ea.WriteHookResponse(message)
+}
+
+// SubagentAwareExtractor
+func (f *fullAgent) ExtractAllModifiedFiles(data []byte, offset int, dir string) ([]string, error) {
+	return f.ea.ExtractAllModifiedFiles(data, offset, dir)
+}
+func (f *fullAgent) CalculateTotalTokenUsage(data []byte, offset int, dir string) (*agent.TokenUsage, error) {
+	return f.ea.CalculateTotalTokenUsage(data, offset, dir)
+}
+
+var (
+	_ agent.HookSupport            = (*fullAgent)(nil)
+	_ agent.TranscriptAnalyzer     = (*fullAgent)(nil)
+	_ agent.TokenCalculator        = (*fullAgent)(nil)
+	_ agent.TextGenerator          = (*fullAgent)(nil)
+	_ agent.HookResponseWriter     = (*fullAgent)(nil)
+	_ agent.SubagentAwareExtractor = (*fullAgent)(nil)
+)
diff --git a/cmd/entire/cli/agent/external/discovery.go b/cmd/entire/cli/agent/external/discovery.go
new file mode 100644
index 0000000..9808be6
--- /dev/null
+++ b/cmd/entire/cli/agent/external/discovery.go
@@ -0,0 +1,88 @@
+package external
+
+import (
+	"context"
+	"log/slog"
+	"os"
+	"path/filepath"
+	"strings"
+
+	"github.com/entireio/cli/cmd/entire/cli/agent"
+	"github.com/entireio/cli/cmd/entire/cli/agent/types"
+	"github.com/entireio/cli/cmd/entire/cli/logging"
+)
+
+const binaryPrefix = "entire-agent-"
+
+// DiscoverAndRegister scans $PATH for executables matching "entire-agent-<name>",
+// calls their "info" subcommand, and registers them in the agent registry.
+// Binaries whose name conflicts with an already-registered agent are skipped.
+// Errors during discovery are logged but do not prevent other agents from loading.
+func DiscoverAndRegister(ctx context.Context) {
+	pathEnv := os.Getenv("PATH")
+	if pathEnv == "" {
+		return
+	}
+
+	// Collect already-registered names to avoid conflicts.
+	registered := make(map[types.AgentName]bool)
+	for _, name := range agent.List() {
+		registered[name] = true
+	}
+
+	seen := make(map[string]bool) // deduplicate binaries across PATH dirs
+	for _, dir := range filepath.SplitList(pathEnv) {
+		entries, err := os.ReadDir(dir)
+		if err != nil {
+			continue // skip unreadable directories
+		}
+		for _, entry := range entries {
+			name := entry.Name()
+			if !strings.HasPrefix(name, binaryPrefix) {
+				continue
+			}
+			if seen[name] {
+				continue
+			}
+			seen[name] = true
+
+			agentName := types.AgentName(strings.TrimPrefix(name, binaryPrefix))
+			if registered[agentName] {
+				logging.Debug(ctx, "skipping external agent (name conflict with built-in)",
+					slog.String("binary", name),
+					slog.String("agent", string(agentName)))
+				continue
+			}
+
+			binPath := filepath.Join(dir, name)
+			finfo, err := os.Stat(binPath) //nolint:gosec // PATH entries are trusted //nolint:gosec // PATH entries are trusted
+			if err != nil || finfo.IsDir() {
+				continue
+			}
+			// Check executable bit (on Unix)
+			if finfo.Mode()&0o111 == 0 {
+				continue
+			}
+
+			ea, err := New(binPath)
+			if err != nil {
+				logging.Debug(ctx, "skipping external agent (info failed)",
+					slog.String("binary", binPath),
+					slog.String("error", err.Error()))
+				continue
+			}
+
+			// Wrap with capability interfaces and register
+			wrapped := Wrap(ea)
+			agent.Register(agentName, func() agent.Agent {
+				return wrapped
+			})
+			registered[agentName] = true
+
+			logging.Debug(ctx, "registered external agent",
+				slog.String("name", string(agentName)),
+				slog.String("type", string(ea.Type())),
+				slog.String("binary", binPath))
+		}
+	}
+}
diff --git a/cmd/entire/cli/agent/external/external.go b/cmd/entire/cli/agent/external/external.go
new file mode 100644
index 0000000..05f0bef
--- /dev/null
+++ b/cmd/entire/cli/agent/external/external.go
@@ -0,0 +1,506 @@
+package external
+
+import (
+	"bytes"
+	"context"
+	"encoding/json"
+	"fmt"
+	"io"
+	"os/exec"
+	"strconv"
+	"time"
+
+	"github.com/entireio/cli/cmd/entire/cli/agent"
+	"github.com/entireio/cli/cmd/entire/cli/agent/types"
+	"github.com/entireio/cli/cmd/entire/cli/paths"
+)
+
+// Agent implements agent.Agent by delegating to an external binary.
+// Each method invokes a subcommand on the binary and parses the JSON response.
+type Agent struct {
+	binaryPath string
+	info       *InfoResponse
+}
+
+// New creates an Agent by calling the binary's "info" subcommand
+// to cache its metadata. Returns an error if the binary cannot be invoked or returns
+// invalid/incompatible protocol data.
+func New(binaryPath string) (*Agent, error) {
+	ea := &Agent{binaryPath: binaryPath}
+
+	stdout, err := ea.run(context.Background(), nil, "info")
+	if err != nil {
+		return nil, fmt.Errorf("info: %w", err)
+	}
+
+	var info InfoResponse
+	if err := json.Unmarshal(stdout, &info); err != nil {
+		return nil, fmt.Errorf("info: invalid JSON: %w", err)
+	}
+
+	if info.ProtocolVersion != ProtocolVersion {
+		return nil, fmt.Errorf("protocol version mismatch: binary reports %d, expected %d",
+			info.ProtocolVersion, ProtocolVersion)
+	}
+
+	ea.info = &info
+	return ea, nil
+}
+
+// Info returns the cached info response.
+func (e *Agent) Info() *InfoResponse {
+	return e.info
+}
+
+// --- Agent interface: Identity ---
+
+func (e *Agent) Name() types.AgentName {
+	return types.AgentName(e.info.Name)
+}
+
+func (e *Agent) Type() types.AgentType {
+	return types.AgentType(e.info.Type)
+}
+
+func (e *Agent) Description() string {
+	return e.info.Description
+}
+
+func (e *Agent) IsPreview() bool {
+	return e.info.IsPreview
+}
+
+func (e *Agent) DetectPresence(ctx context.Context) (bool, error) {
+	stdout, err := e.run(ctx, nil, "detect")
+	if err != nil {
+		return false, fmt.Errorf("detect: %w", err)
+	}
+	var resp DetectResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return false, fmt.Errorf("detect: invalid JSON: %w", err)
+	}
+	return resp.Present, nil
+}
+
+func (e *Agent) ProtectedDirs() []string {
+	return e.info.ProtectedDirs
+}
+
+// --- Agent interface: Transcript Storage ---
+
+func (e *Agent) ReadTranscript(sessionRef string) ([]byte, error) {
+	return e.run(context.Background(), nil, "read-transcript", "--session-ref", sessionRef)
+}
+
+func (e *Agent) ChunkTranscript(ctx context.Context, content []byte, maxSize int) ([][]byte, error) {
+	stdout, err := e.run(ctx, content, "chunk-transcript", "--max-size", strconv.Itoa(maxSize))
+	if err != nil {
+		return nil, fmt.Errorf("chunk-transcript: %w", err)
+	}
+	var resp ChunkResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, fmt.Errorf("chunk-transcript: invalid JSON: %w", err)
+	}
+	return resp.Chunks, nil
+}
+
+func (e *Agent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
+	input, err := json.Marshal(ChunkResponse{Chunks: chunks})
+	if err != nil {
+		return nil, fmt.Errorf("reassemble-transcript: marshal: %w", err)
+	}
+	return e.run(context.Background(), input, "reassemble-transcript")
+}
+
+// --- Agent interface: Legacy methods ---
+
+func (e *Agent) GetSessionID(input *agent.HookInput) string {
+	data, err := marshalHookInput(input)
+	if err != nil {
+		return ""
+	}
+	stdout, err := e.run(context.Background(), data, "get-session-id")
+	if err != nil {
+		return ""
+	}
+	var resp SessionIDResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return ""
+	}
+	return resp.SessionID
+}
+
+func (e *Agent) GetSessionDir(repoPath string) (string, error) {
+	stdout, err := e.run(context.Background(), nil, "get-session-dir", "--repo-path", repoPath)
+	if err != nil {
+		return "", fmt.Errorf("get-session-dir: %w", err)
+	}
+	var resp SessionDirResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return "", fmt.Errorf("get-session-dir: invalid JSON: %w", err)
+	}
+	return resp.SessionDir, nil
+}
+
+func (e *Agent) ResolveSessionFile(sessionDir, agentSessionID string) string {
+	stdout, err := e.run(context.Background(), nil, "resolve-session-file",
+		"--session-dir", sessionDir, "--session-id", agentSessionID)
+	if err != nil {
+		return ""
+	}
+	var resp SessionFileResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return ""
+	}
+	return resp.SessionFile
+}
+
+func (e *Agent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
+	data, err := marshalHookInput(input)
+	if err != nil {
+		return nil, fmt.Errorf("read-session: marshal: %w", err)
+	}
+	stdout, err := e.run(context.Background(), data, "read-session")
+	if err != nil {
+		return nil, fmt.Errorf("read-session: %w", err)
+	}
+	var resp AgentSessionJSON
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, fmt.Errorf("read-session: invalid JSON: %w", err)
+	}
+	return unmarshalAgentSession(&resp)
+}
+
+func (e *Agent) WriteSession(ctx context.Context, session *agent.AgentSession) error {
+	data, err := marshalAgentSession(session)
+	if err != nil {
+		return fmt.Errorf("write-session: marshal: %w", err)
+	}
+	_, err = e.run(ctx, data, "write-session")
+	if err != nil {
+		return fmt.Errorf("write-session: %w", err)
+	}
+	return nil
+}
+
+func (e *Agent) FormatResumeCommand(sessionID string) string {
+	stdout, err := e.run(context.Background(), nil, "format-resume-command", "--session-id", sessionID)
+	if err != nil {
+		return ""
+	}
+	var resp ResumeCommandResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return ""
+	}
+	return resp.Command
+}
+
+// --- HookSupport methods (delegated when capabilities.hooks is true) ---
+
+func (e *Agent) HookNames() []string {
+	return e.info.HookNames
+}
+
+func (e *Agent) ParseHookEvent(ctx context.Context, hookName string, stdin io.Reader) (*agent.Event, error) {
+	data, err := io.ReadAll(stdin)
+	if err != nil {
+		return nil, fmt.Errorf("parse-hook: read stdin: %w", err)
+	}
+	stdout, err := e.run(ctx, data, "parse-hook", "--hook", hookName)
+	if err != nil {
+		return nil, fmt.Errorf("parse-hook: %w", err)
+	}
+	// null means no lifecycle significance
+	if bytes.Equal(bytes.TrimSpace(stdout), []byte("null")) {
+		return nil, nil //nolint:nilnil // protocol contract: null = no event
+	}
+	var event eventJSON
+	if err := json.Unmarshal(stdout, &event); err != nil {
+		return nil, fmt.Errorf("parse-hook: invalid JSON: %w", err)
+	}
+	return event.toEvent()
+}
+
+func (e *Agent) InstallHooks(ctx context.Context, localDev bool, force bool) (int, error) {
+	args := []string{"install-hooks"}
+	if localDev {
+		args = append(args, "--local-dev")
+	}
+	if force {
+		args = append(args, "--force")
+	}
+	stdout, err := e.run(ctx, nil, args...)
+	if err != nil {
+		return 0, fmt.Errorf("install-hooks: %w", err)
+	}
+	var resp HooksInstalledCountResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return 0, fmt.Errorf("install-hooks: invalid JSON: %w", err)
+	}
+	return resp.HooksInstalled, nil
+}
+
+func (e *Agent) UninstallHooks(ctx context.Context) error {
+	_, err := e.run(ctx, nil, "uninstall-hooks")
+	if err != nil {
+		return fmt.Errorf("uninstall-hooks: %w", err)
+	}
+	return nil
+}
+
+func (e *Agent) AreHooksInstalled(ctx context.Context) bool {
+	stdout, err := e.run(ctx, nil, "are-hooks-installed")
+	if err != nil {
+		return false
+	}
+	var resp AreHooksInstalledResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return false
+	}
+	return resp.Installed
+}
+
+// --- TranscriptAnalyzer methods ---
+
+func (e *Agent) GetTranscriptPosition(path string) (int, error) {
+	stdout, err := e.run(context.Background(), nil, "get-transcript-position", "--path", path)
+	if err != nil {
+		return 0, fmt.Errorf("get-transcript-position: %w", err)
+	}
+	var resp TranscriptPositionResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return 0, fmt.Errorf("get-transcript-position: invalid JSON: %w", err)
+	}
+	return resp.Position, nil
+}
+
+func (e *Agent) ExtractModifiedFilesFromOffset(path string, startOffset int) ([]string, int, error) {
+	stdout, err := e.run(context.Background(), nil, "extract-modified-files",
+		"--path", path, "--offset", strconv.Itoa(startOffset))
+	if err != nil {
+		return nil, 0, fmt.Errorf("extract-modified-files: %w", err)
+	}
+	var resp ExtractFilesResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, 0, fmt.Errorf("extract-modified-files: invalid JSON: %w", err)
+	}
+	return resp.Files, resp.CurrentPosition, nil
+}
+
+func (e *Agent) ExtractPrompts(sessionRef string, fromOffset int) ([]string, error) {
+	stdout, err := e.run(context.Background(), nil, "extract-prompts",
+		"--session-ref", sessionRef, "--offset", strconv.Itoa(fromOffset))
+	if err != nil {
+		return nil, fmt.Errorf("extract-prompts: %w", err)
+	}
+	var resp ExtractPromptsResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, fmt.Errorf("extract-prompts: invalid JSON: %w", err)
+	}
+	return resp.Prompts, nil
+}
+
+func (e *Agent) ExtractSummary(sessionRef string) (string, error) {
+	stdout, err := e.run(context.Background(), nil, "extract-summary", "--session-ref", sessionRef)
+	if err != nil {
+		return "", fmt.Errorf("extract-summary: %w", err)
+	}
+	var resp ExtractSummaryResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return "", fmt.Errorf("extract-summary: invalid JSON: %w", err)
+	}
+	return resp.Summary, nil
+}
+
+// --- TranscriptPreparer methods ---
+
+func (e *Agent) PrepareTranscript(ctx context.Context, sessionRef string) error {
+	_, err := e.run(ctx, nil, "prepare-transcript", "--session-ref", sessionRef)
+	if err != nil {
+		return fmt.Errorf("prepare-transcript: %w", err)
+	}
+	return nil
+}
+
+// --- TokenCalculator methods ---
+
+func (e *Agent) CalculateTokenUsage(transcriptData []byte, fromOffset int) (*agent.TokenUsage, error) {
+	stdout, err := e.run(context.Background(), transcriptData,
+		"calculate-tokens", "--offset", strconv.Itoa(fromOffset))
+	if err != nil {
+		return nil, fmt.Errorf("calculate-tokens: %w", err)
+	}
+	var resp TokenUsageResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, fmt.Errorf("calculate-tokens: invalid JSON: %w", err)
+	}
+	return convertTokenUsage(&resp), nil
+}
+
+// --- TextGenerator methods ---
+
+func (e *Agent) GenerateText(ctx context.Context, prompt string, model string) (string, error) {
+	stdout, err := e.run(ctx, []byte(prompt), "generate-text", "--model", model)
+	if err != nil {
+		return "", fmt.Errorf("generate-text: %w", err)
+	}
+	var resp GenerateTextResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return "", fmt.Errorf("generate-text: invalid JSON: %w", err)
+	}
+	return resp.Text, nil
+}
+
+// --- HookResponseWriter methods ---
+
+func (e *Agent) WriteHookResponse(message string) error {
+	_, err := e.run(context.Background(), nil, "write-hook-response", "--message", message)
+	if err != nil {
+		return fmt.Errorf("write-hook-response: %w", err)
+	}
+	return nil
+}
+
+// --- SubagentAwareExtractor methods ---
+
+func (e *Agent) ExtractAllModifiedFiles(transcriptData []byte, fromOffset int, subagentsDir string) ([]string, error) {
+	stdout, err := e.run(context.Background(), transcriptData,
+		"extract-all-modified-files", "--offset", strconv.Itoa(fromOffset), "--subagents-dir", subagentsDir)
+	if err != nil {
+		return nil, fmt.Errorf("extract-all-modified-files: %w", err)
+	}
+	var resp ExtractFilesResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, fmt.Errorf("extract-all-modified-files: invalid JSON: %w", err)
+	}
+	return resp.Files, nil
+}
+
+func (e *Agent) CalculateTotalTokenUsage(transcriptData []byte, fromOffset int, subagentsDir string) (*agent.TokenUsage, error) {
+	stdout, err := e.run(context.Background(), transcriptData,
+		"calculate-total-tokens", "--offset", strconv.Itoa(fromOffset), "--subagents-dir", subagentsDir)
+	if err != nil {
+		return nil, fmt.Errorf("calculate-total-tokens: %w", err)
+	}
+	var resp TokenUsageResponse
+	if err := json.Unmarshal(stdout, &resp); err != nil {
+		return nil, fmt.Errorf("calculate-total-tokens: invalid JSON: %w", err)
+	}
+	return convertTokenUsage(&resp), nil
+}
+
+// run executes a subcommand on the external binary and returns stdout bytes.
+// If stdin is non-nil it is piped to the process. On non-zero exit, stderr is
+// included in the returned error.
+func (e *Agent) run(ctx context.Context, stdin []byte, args ...string) ([]byte, error) {
+	cmd := exec.CommandContext(ctx, e.binaryPath, args...)
+
+	// Set environment: repo root + protocol version
+	cmd.Env = append(cmd.Environ(),
+		"ENTIRE_PROTOCOL_VERSION="+strconv.Itoa(ProtocolVersion),
+	)
+	if repoRoot, err := paths.WorktreeRoot(ctx); err == nil {
+		cmd.Env = append(cmd.Env, "ENTIRE_REPO_ROOT="+repoRoot)
+		cmd.Dir = repoRoot
+	}
+
+	if stdin != nil {
+		cmd.Stdin = bytes.NewReader(stdin)
+	}
+
+	var stdoutBuf, stderrBuf bytes.Buffer
+	cmd.Stdout = &stdoutBuf
+	cmd.Stderr = &stderrBuf
+
+	if err := cmd.Run(); err != nil {
+		errMsg := stderrBuf.String()
+		if errMsg != "" {
+			return nil, fmt.Errorf("%s: %s", args[0], errMsg)
+		}
+		return nil, fmt.Errorf("%s: %w", args[0], err)
+	}
+
+	return stdoutBuf.Bytes(), nil
+}
+
+// --- Helpers ---
+
+func marshalHookInput(input *agent.HookInput) ([]byte, error) {
+	if input == nil {
+		return []byte("{}"), nil
+	}
+	j := HookInputJSON{
+		HookType:   string(input.HookType),
+		SessionID:  input.SessionID,
+		SessionRef: input.SessionRef,
+		Timestamp:  input.Timestamp.Format(time.RFC3339),
+		UserPrompt: input.UserPrompt,
+		ToolName:   input.ToolName,
+		ToolUseID:  input.ToolUseID,
+		ToolInput:  input.ToolInput,
+		RawData:    input.RawData,
+	}
+	data, err := json.Marshal(j)
+	if err != nil {
+		return nil, fmt.Errorf("marshal hook input: %w", err)
+	}
+	return data, nil
+}
+
+func marshalAgentSession(s *agent.AgentSession) ([]byte, error) {
+	j := AgentSessionJSON{
+		SessionID:     s.SessionID,
+		AgentName:     string(s.AgentName),
+		RepoPath:      s.RepoPath,
+		SessionRef:    s.SessionRef,
+		StartTime:     s.StartTime.Format(time.RFC3339),
+		NativeData:    s.NativeData,
+		ModifiedFiles: s.ModifiedFiles,
+		NewFiles:      s.NewFiles,
+		DeletedFiles:  s.DeletedFiles,
+	}
+	data, err := json.Marshal(j)
+	if err != nil {
+		return nil, fmt.Errorf("marshal agent session: %w", err)
+	}
+	return data, nil
+}
+
+func unmarshalAgentSession(j *AgentSessionJSON) (*agent.AgentSession, error) {
+	var startTime time.Time
+	if j.StartTime != "" {
+		var err error
+		startTime, err = time.Parse(time.RFC3339, j.StartTime)
+		if err != nil {
+			return nil, fmt.Errorf("invalid start_time: %w", err)
+		}
+	}
+	return &agent.AgentSession{
+		SessionID:     j.SessionID,
+		AgentName:     types.AgentName(j.AgentName),
+		RepoPath:      j.RepoPath,
+		SessionRef:    j.SessionRef,
+		StartTime:     startTime,
+		NativeData:    j.NativeData,
+		ModifiedFiles: j.ModifiedFiles,
+		NewFiles:      j.NewFiles,
+		DeletedFiles:  j.DeletedFiles,
+	}, nil
+}
+
+func convertTokenUsage(r *TokenUsageResponse) *agent.TokenUsage {
+	if r == nil {
+		return nil
+	}
+	usage := &agent.TokenUsage{
+		InputTokens:         r.InputTokens,
+		CacheCreationTokens: r.CacheCreationTokens,
+		CacheReadTokens:     r.CacheReadTokens,
+		OutputTokens:        r.OutputTokens,
+		APICallCount:        r.APICallCount,
+	}
+	if r.SubagentTokens != nil {
+		usage.SubagentTokens = convertTokenUsage(r.SubagentTokens)
+	}
+	return usage
+}
